private string ResolveChildPath(string dir, string fileName)
{
    var leafName = Path.GetFileName(fileName);
    if (string.IsNullOrWhiteSpace(leafName) || leafName.IndexOfAny(Path.GetInvalidFileNameChars()) >= 0)
    {
        throw new ArgumentException("Invalid file name");
    }

    var root = Root;
    var path = Path.GetFullPath(Path.Combine(dir, leafName));

